import React, { useEffect, useRef } from 'react';
import './Hero.css';

// Founder photo embedded as base64 (replace with import founderImg from '../assets/founder.jpg' if preferred)
const FOUNDER_IMG = "data:image/jpeg;base64,";

const testimonials = [
  { av:'RP', text:'"NodeNexus delivered our clinic site in under 2 weeks. Stunning and fast." — Dr. Ramya Priya' },
  { av:'AK', text:'"New patient enquiries came in the first week." — Arun K., Practice Manager' },
  { av:'SR', text:'"Professional, responsive, genuinely detail-oriented." — Sundari R.' },
  { av:'VJ', text:'"Understood our vision immediately. Clean, fast, perfect." — Vijay J.' },
];

const STACK_TAGS = ['React.js','Next.js','Node.js','TypeScript','HTML/CSS','SEO'];

const STATS = [
  { num:'1', sup:'+',   label:'Project Launched'   },
  { num:'100', sup:'%', label:'Client Satisfaction' },
  { num:'2',   sup:'wk',label:'Avg. Delivery'       },
  { num:'90',  sup:'+', label:'Lighthouse Score'    },
];

export default function Hero() {
  const gridRef = useRef(null);

  // Parallax scroll on grid
  useEffect(() => {
    const onScroll = () => {
      if (!gridRef.current) return;
      const y = window.scrollY;
      gridRef.current.style.transform = `translateY(${y * 0.3}px) scale(${1 + y * 0.00012})`;
    };
    // Mouse-parallax on grid
    const onMouse = (e) => {
      if (!gridRef.current) return;
      const rx = (e.clientX / window.innerWidth  - 0.5) * 10;
      const ry = (e.clientY / window.innerHeight - 0.5) * 10;
      gridRef.current.style.transform = `translate(${rx}px, ${ry}px)`;
    };
    window.addEventListener('scroll',    onScroll, { passive:true });
    document.addEventListener('mousemove', onMouse);
    return () => {
      window.removeEventListener('scroll',    onScroll);
      document.removeEventListener('mousemove', onMouse);
    };
  }, []);

  // Duplicate testimonials for seamless loop
  const doubled = [...testimonials, ...testimonials];

  return (
    <section id="hero" className="hero">
      {/* Background layer */}
      <div className="hero-bg">
        <div className="hero-grid" ref={gridRef} />
        <div className="hero-orb1" />
        <div className="hero-orb2" />
      </div>

      {/* Founder photo — right panel */}
      <div className="hero-right">
        <img src={FOUNDER_IMG} alt="NodeNexus founder" className="hero-photo" />
        <div className="hero-photo-overlay" />
        <div className="hero-photo-fade" />
        <div className="hero-photo-bottom" />
      </div>

      {/* Main content — left */}
      <div className="hero-left">
        <div className="hero-badge">
          <span className="badge-pulse" />
          Open for projects — Salem, TN
        </div>

        <h1 className="hero-title">
          Web &amp; React<br />
          <span className="accent">Development</span><br />
          That Delivers
        </h1>

        <p className="hero-sub">
          NodeNexus builds fast, modern websites and React applications for businesses
          that want real results — not templates. Your vision, coded with precision.
        </p>

        <div className="hero-btns">
          <a href="#projects" className="btn-primary">See Our Work</a>
          <a href="#pricing"  className="btn-secondary">View Pricing →</a>
        </div>

        <div className="hero-stacks">
          {STACK_TAGS.map(t => <span key={t} className="stack-tag">{t}</span>)}
        </div>
      </div>

      {/* Stats */}
      <div className="hero-stats">
        {STATS.map(s => (
          <div key={s.label} className="stat">
            <span className="stat-num">{s.num}<em>{s.sup}</em></span>
            <span className="stat-label">{s.label}</span>
          </div>
        ))}
      </div>

      {/* Scrolling testimonials strip */}
      <div className="testi-strip">
        <div className="testi-scroll">
          {doubled.map((t, i) => (
            <div key={i} className="t-item">
              <div className="t-av">{t.av}</div>
              <span className="t-stars">★★★★★</span>
              <span className="t-txt">{t.text}</span>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
